let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| where '*' in (reporterFilter) or ReportOrgName in (reporterFilter)
| summarize arg_max(TimeGenerated, PolicyPublished_p, PolicyPublished_sp, PolicyPublished_pct, PolicyPublished_adkim, PolicyPublished_aspf) by Domain
| project Domain, Policy=PolicyPublished_p, SubdomainPolicy=PolicyPublished_sp, Pct=PolicyPublished_pct, DKIM_Alignment=PolicyPublished_adkim, SPF_Alignment=PolicyPublished_aspf

let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
let expectedReporters = dynamic(['google.com', 'microsoft.com', 'yahoo.com', 'comcast.net', 'apple.com', 'fastmail.com', 'zoho.com']);
let activeReporters = DMARCReports_CL
| where TimeGenerated > ago(30d)
| where '*' in (domainFilter) or Domain in (domainFilter)
| where '*' in (reporterFilter) or ReportOrgName in (reporterFilter)
| distinct tolower(ReportOrgName);
print ExpectedReporters = expectedReporters
| mv-expand Reporter = ExpectedReporters
| extend Reporter = tostring(Reporter)
| where Reporter !in (activeReporters)
| project MissingReporter = Reporter, Note = 'No reports received in the last 30 days. Check DMARC DNS record rua tag.'

let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
